import{_ as e,o,c as a,ae as i}from"./chunks/framework.BzQXgbNp.js";const u=JSON.parse('{"title":"🗑️ 虛擬垃圾桶系統 (Wastebin)","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Wastebin.md","filePath":"Mc-Wastebin.md"}'),l={name:"Mc-Wastebin.md"};function n(s,t,r,c,d,g){return o(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="🗑️-虛擬垃圾桶系統-wastebin" tabindex="-1">🗑️ 虛擬垃圾桶系統 (Wastebin) <a class="header-anchor" href="#🗑️-虛擬垃圾桶系統-wastebin" aria-label="Permalink to &quot;🗑️ 虛擬垃圾桶系統 (Wastebin)&quot;">​</a></h1><p>當您的背包堆滿不需要的垃圾物品（如無用的石頭、泥土或垃圾裝備）時，可以使用伺服器提供的安全虛擬垃圾桶快速清理。</p><hr><h2 id="🚮-使用方法與銷毀機制" tabindex="-1">🚮 使用方法與銷毀機制 <a class="header-anchor" href="#🚮-使用方法與銷毀機制" aria-label="Permalink to &quot;🚮 使用方法與銷毀機制&quot;">​</a></h2><ol><li><strong>開啟垃圾桶</strong>： <ul><li>在遊戲中輸入指令 <strong><code>/wastebin</code></strong>。</li><li>系統會為您彈出一個 <strong>27 格（單個箱子大小）</strong> 的個人專屬虛擬垃圾箱。</li></ul></li><li><strong>放入垃圾與關閉</strong>： <ul><li>將您要丟棄的物品直接放入該垃圾箱中，然後按 <code>Esc</code> 或點選右上角 <code>X</code> 關閉介面。</li></ul></li><li><strong>10 秒倒數與緩衝</strong>： <ul><li>關閉垃圾箱後，物品<strong>不會立刻消失</strong>，而是會啟動 <strong>10 秒銷毀倒數計時器</strong>，聊天欄會顯示：<code>§b[Craft-Core] §e垃圾桶已關閉，將於 10 秒後徹底銷毀暫存物品！(再次打開可取消銷毀)</code>。</li></ul></li><li><strong>防誤刪拯救機制</strong>： <ul><li>如果您不小心丟錯了貴重物品，只要在關閉後的 <strong>10 秒內再次輸入 <code>/wastebin</code> 打開垃圾桶</strong>，倒數計時器將被立即取消重置！</li><li>您的物品會完好無損地保留在垃圾桶中，您可以將其拿回背包。再次關閉垃圾桶後，將重新起算 10 秒倒數。</li></ul></li><li><strong>徹底銷毀</strong>： <ul><li>當 10 秒到期且您未再次打開垃圾桶，其中的所有暫存物品將被徹底銷毀清空，不可復原。</li></ul></li></ol>',5)])])}const b=e(l,[["render",n]]);export{u as __pageData,b as default};
